**DHT22 Sıcaklık ve Nem Sensörü Okuma**

DHT22: -40°C ile +80°C arası ±0.5°C hassasiyet, %0-100 nem:

```python
# Raspberry Pi
import Adafruit_DHT
import time

SENSOr_TIPI = Adafruit_DHT.DHT22
PIN = 4  # GPIO 4

def dht22_oku(deneme=3):
    for _ in range(deneme):
        nem, sicaklik = Adafruit_DHT.read_retry(SENSOR_TIPI, PIN)
        if sicaklik is not None and nem is not None:
            return round(sicaklik, 1), round(nem, 1)
        time.sleep(2)
    return None, None

while True:
    s, n = dht22_oku()
    if s and n:
        print(f'Sıcaklık: {s}°C, Nem: {n}%')
        # MQTT'ye gönder
        client.publish('ev/sicaklik', s, qos=0)
        client.publish('ev/nem', n, qos=0)
    time.sleep(30)  # DHT22 min 2 sn bekleme gerektirir

