from collections import deque
class MovingAverage:
    def __init__(self, window=10):
        self.buffer = deque(maxlen=window)
    def update(self, val):
        self.buffer.append(val)
        return sum(self.buffer) / len(self.buffer)

f = MovingAverage(10)
for raw in sensor_readings:
